#include "FreeRTOS.h"
#include "task.h"

void vSensorTask(void *pvParameters) {
    TickType_t xLastWakeTime = xTaskGetTickCount();
    const TickType_t xPeriod = pdMS_TO_TICKS(100); // 100ms

    for (;;) {
        float temp = read_temperature_sensor();
        float humidity = read_humidity_sensor();

        // Send to queue for processing
        SensorData_t data = {temp, humidity, xTaskGetTickCount()};
        xQueueSend(xSensorQueue, &data, pdMS_TO_TICKS(10));

        vTaskDelayUntil(&xLastWakeTime, xPeriod);
    }
}

// Create task (in main):
xTaskCreate(vSensorTask, "Sensor", 256, NULL, 2, &xSensorHandle);
```
Stack size 256 words (1KB) is typical for simple sensor tasks. Priority 2 (above idle, below critical).

