    for (;;) {
        SensorData_t sample = acquire_sample();
        if (xQueueSend(xDataQueue, &sample, pdMS_TO_TICKS(50)) != pdTRUE) {
            // Queue full — log overflow, drop oldest or block
            overflows++;
        }
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

// Consumer task:
void vConsumerTask(void *pv) {
    SensorData_t received;
    for (;;) {
        if (xQueueReceive(xDataQueue, &received, portMAX_DELAY) == pdTRUE) {
            process_and_transmit(received);
        }
    }
}
